function LFightHud:LFightHud(cache, colIndex)
    ---@type LFightCache
    self._battleCache = cache
    --挂载父节点
    self._parentTrans = self._battleCache:GetHudRootTransByColIndex(colIndex)

    self._wordRootTrans = self._battleCache:GetWordRootTrans()
    --hud数据
    self._hudDataList = nil

    self._btNodeTrans = nil

    ---@type LFightHudItem
    self._btNodeItem = nil

    --- {hudType=1,trans=trans,tween=tween}
    self._hudShowList = nil

    --上次obj 位置在界面上的世界坐标
    self._lastWorldPos = nil

    self._curIndex = 0

    self._maxIndex = 0

    self._nextDelay = nil

    self._playendCount = 0

    self._isLast = false

    self._isDestroyed = false

    -- 左边还是右边
    self._isLeft = true

    self._group = 0
    self._idx = 0

    self._designXRange = LGameQuality.SCREEN_WIDTH_DESIGN * 0.5 --设计界面边界


    ---@type LFightSkill
    self._battleSkill = nil
end
-----------------------------------------------------------------
function LFightHud:PlayHitAction()
    local hitAction
    if self._hudPara then
        hitAction = self._hudPara.hitAction
    end
    if not hitAction then
        hitAction = self._recordHitAction
    end
    if not hitAction then return end

    ---@type LFightObject
    local tarObj = self._tarObj
    if not tarObj then return end

    if hitAction == LFightConst.HIT_ACT_SOUND_ONLY then
        tarObj:PlayHitSound()
    elseif hitAction == LFightConst.HIT_ACT_SOUND_AND_SKILLHIT then
        if tarObj:IsCanPlayHit() then
            tarObj:PlaySkillHitAni()
        end
        tarObj:PlayHitSound()
    elseif hitAction == LFightConst.HIT_ACT_SOUND_AND_HIT then
        if tarObj:IsCanPlayHit() then
            tarObj:PlayHitAni()
        end
        tarObj:PlayHitSound()
    end
end

function LFightHud:SetTarObj(tarObj)
    self._tarObj = tarObj
end

---@param battleSkill LFightSkill
function LFightHud:SetBattleSkill(battleSkill)
    self._battleSkill = battleSkill
end

