---往上顶
function LFightHud:UpBtNodePos(posY)
    local pos = self._btNodeTrans.localPosition
    pos.y = pos.y + posY
    self._btNodeTrans.localPosition = pos
end

function LFightHud:SetGroupOffset(offsetCnt)
    local offset = Vector3.New(0,20*offsetCnt,0)
    local curOffset = self._btNodeTrans.localPosition
    if curOffset.y< offset.y then
        self._btNodeTrans.localPosition = offset
    end
end

function LFightHud:SetRandX()
    local minX = -5
    local maxX = 5
    local randX = math.random() * (maxX - minX) + minX
    self._randPosX = randX
end

function LFightHud:IsPlaying()
    return self._isPlaying
end

function LFightHud:GetGroup()
    return self._group
end

function LFightHud:GetIdx()
    return self._idx
end

function LFightHud:GetStartTime()
    return self._startTime
end

-------------------------------------------------------------------
function LFightHud:ShowBtNode()
    if self._hudType == LFightConst.HUD_SKILL then
        if not gLGameUI:IsVisibleBattleFont() then return end

        local btHudFollow = self._btNodeItem:GetBtHudFollow(self._btNodeTrans)
        if btHudFollow then
            local followPos
            local obj = self._tarObj
            local followTrans = nil
            if obj and not obj:IsDestroy() then
                followPos = obj:GetTopNodePos()
                followTrans = obj:GetDpObject():GetDisplayTrans()
            end
            local sceneCamera = gLGameScene:GetCurrentSceneCamera()
            local uiSceneCamrea = LGameUI.GetUICamera()
            btHudFollow:Init(uiSceneCamrea,sceneCamera)
            btHudFollow:DoFollowTrans(followTrans, followPos or Vector3(0,0,0))
        end
        self._btHudFollow = btHudFollow
    end
    CS.ShowObject(self._btNodeTrans,true)
end

---开始下一个hud的表现
function LFightHud:ShowNextHud()
    local oldIndex = self._curIndex
    if oldIndex >= self._maxIndex then
        self._isLast = true
        return
    end

    local idx = oldIndex + 1
    self._curIndex = idx

    if idx == 1 then
        self:ShowBtNode()
    end

    local spurtingTime = 0
    if self._tarObj then
        if not self._isPlaySpurting then
            if self._battleSkill then
                local time = self._battleSkill:ExecutePlaySpurting(self._tarObj:GetId())
                if time and time > 0 then
                    self._recordHitAction = self._hudPara.hitAction
                    spurtingTime = time
                    self._isPlaySpurting = true
                end
            end
        end
    end


    local hudShowData = self._hudShowList[idx]
    local oldShowData = self._hudShowList[oldIndex]
    local hudData = hudShowData.data
    local trans = hudShowData.trans
    self._isLast = idx >= self._maxIndex
    local nextData = self._hudDataList[idx + 1]
    local nextDelay = nextData and nextData:GetDelay() or 0
    self._nextDelay = nextDelay + spurtingTime

    local pos = self:GetObjPos()
    if pos then
        self._lastWorldPos = pos
    end

    --设置节点的世界坐标
    if self._lastWorldPos then trans.position = self._lastWorldPos end

    if self._group == LFightConst.HUD_GROUP_HURT then
        --x轴在小范围内偏移，错位一下
        self:SetRandX()
        local nowPos = trans.localPosition
        local nowX = nowPos.x + self._randPosX
        if hudShowData.textPosX then
            if self._isLeft then
                local allWidth = -hudShowData.textPosX - (hudShowData.textWidth or 0)
                --判断出界
                local worldPos = trans:TransformPoint(Vector3(allWidth, 0, 0))
                local tmpPos = trans.parent:InverseTransformPoint(worldPos)
                local range = tmpPos.x
                if range < -self._designXRange then
                    nowX = nowX + self._designXRange + range + (-allWidth) / 2 + 50
                    nowX = nowX - self._randPosX
                end
            else
                --判断出界
                local worldPos = trans:TransformPoint(Vector3(hudShowData.textPosX + (hudShowData.textWidth or 0), 0, 0))
                local tmpPos = trans.parent:InverseTransformPoint(worldPos)
                local range = tmpPos.x
                if range > self._designXRange then
                    nowX = nowX + self._designXRange - range - 5
                    nowX = nowX + self._randPosX
                end
            end
        end
        nowPos.x = nowX

        if self._tarObj then
            local gridIndex = self._tarObj:GetIndex() or 0
            --#4069同一列相邻的飘血，高度上需要做一点错开
            if gridIndex == 4 or gridIndex == 5 or gridIndex == 6 then
                nowPos.y = nowPos.y - 25
            end
        end
        trans.localPosition = nowPos
    end

    local seqtween = YXTween.TweenSequenceIns()
    seqtween:AppendInterval(spurtingTime)
    seqtween:AppendCallback(function()
        CS.ShowObject(trans,true)
        self:PlayHitAction()
    end)
    self:CreateAnim(trans,seqtween)
    seqtween:OnComplete(function()
        self._playendCount = self._playendCount + 1
        self._hudShowList[idx].tween = nil
    end)

    hudShowData.tween = seqtween
    seqtween:PlayForward()
end

function LFightHud:ExecuteHitAni(idx,oldIndex)
end

function LFightHud:CreateAnim(trans,seqtween)
    local hudAnim = self._hudPara.animation
    if hudAnim == LFightConst.HUD_ANIM_LEFT_TO_RIGHT or hudAnim == LFightConst.HUD_ANIM_RIGHT_TO_LEFT then
        return self:CreateLtoR_or_RtoLAnim(trans, hudAnim,seqtween)
    else
        return self:CreateDefaultAnim(trans, hudAnim,seqtween)
    end
end

function LFightHud:CreateDefaultAnim(trans, hudAnim,seqtween)
    if not CS.IsValidObject(trans) then return end

    --初始化状态
    local canvasGroup = trans:GetComponent(typeofCanvasGroup)
    canvasGroup.alpha = 1

    local isBuffHud = self._hudType == LFightConst.HUD_BUFF
    local stayTime = isBuffHud and 0.3 or 0 -- 停留时间
    local moveY = 20

    if isBuffHud then
        --buff飘的区域高度加高，2行字左右高度
        moveY = moveY + 18
    end

    local moveTime = 0.5
    local alphaTime = 0.5 -- alpha 消失时间
    local large = Vector3(2,2,2)        -- 大
    local middle = Vector3(1.5,1.5,1.5) -- 中
    local small = Vector3(1,1,1)        -- 小
    local size = self._hudType == LFightConst.HUD_CRIT and large or middle

    local alphaStartPos = stayTime + moveTime - alphaTime + 0.5


    --放大
    local sizeTween = trans:DOScale(size,0.1):SetEase(EaseOutCubic)
    seqtween:Append(sizeTween)

    --缩小
    local smallTween = trans:DOScale(small,0.1):SetEase(EaseOutCubic)
    seqtween:Append(smallTween)

    seqtween:AppendInterval(stayTime)

    --alpha 动画消失
    local alphaTween = canvasGroup:DOFade(0,alphaTime):SetEase(EaseInSine)

    -- Y移动动画
    local moveTween = trans:DOLocalMoveY(trans.localPosition.y + moveY,moveTime)

    seqtween:Append(moveTween)
    seqtween:Insert(alphaStartPos,alphaTween)
    return seqtween
end

function LFightHud:CreateLtoR_or_RtoLAnim(trans, hudAnim,seqtween)
    if not CS.IsValidObject(trans) then return end

    local nowPos = trans.localPosition

    local moveX = 15
    local offsetX = -30
    if hudAnim == LFightConst.HUD_ANIM_LEFT_TO_RIGHT then
        moveX = -moveX
        offsetX = -offsetX
    end
    nowPos.x = nowPos.x + offsetX + moveX
    trans.localPosition = nowPos

    --初始化状态
    local canvasGroup = trans:GetComponent(typeofCanvasGroup)
    canvasGroup.alpha = 1

    local stayTime = 1 -- 停留时间

    local moveTime = 0.5
    local alphaTime = 0.5 -- alpha 消失时间
    local middle = Vector3(1.5,1.5,1.5) -- 中
    local small = Vector3(1,1,1)        -- 小
    local size = middle

    local alphaStartPos = stayTime + moveTime - alphaTime + 0.5


        --放大
    local sizeTween = trans:DOScale(size,0.1):SetEase(EaseOutCubic)
    seqtween:Append(sizeTween)

    --缩小
    local smallTween = trans:DOScale(small,0.1):SetEase(EaseOutCubic)
    seqtween:Append(smallTween)

    --alpha 动画消失
    local alphaTween = canvasGroup:DOFade(0,alphaTime):SetEase(EaseInSine)

    -- Y移动动画
    local moveTween = trans:DOLocalMoveX(nowPos.x - moveX,moveTime):SetEase(EaseOutCubic)

    seqtween:Append(moveTween)
    seqtween:AppendInterval(stayTime)
    seqtween:Insert(alphaStartPos,alphaTween)
    return seqtween
end


function LFightHud:Create(idx, hudDataList,hudPara)
    self._idx = idx
    self._isStart = false

    self._hudDataList = hudDataList
    self._text = hudPara.text
    self._addOrReduceBuff = hudPara.addOrReduceBuff
    self._lastWorldPos = self:GetObjPos()
    local isLeft = hudPara.isLeft
    if isLeft ~= nil then self._isLeft = isLeft end
    local pos = hudPara.pos
    if pos then
        self._objPos = pos:Clone()
    else
        self._objPos = Vector3(0,0,0)
    end
    self._hudPara = hudPara
    self._group = LFightHud.HurtTypeGroup[hudPara.changeType] or LFightConst.HUD_GROUP_HURT

    self._randPosX = 0
end

function LFightHud:SetStartTime(time)
    self._isStart = true
    self._startTime = time
end

function LFightHud:InitHud()
    if self._isPlaying then return end
    self._isPlaying = true
    self:PrepareAllHud()
    self:ShowNextHud()
end

--初始化所有的伤害
function LFightHud:PrepareAllHud()
    local btNodeItem = self._battleCache:GetHudItemFromCache(LFightConst.HUD_BTNODE)
    self._btNodeItem = btNodeItem
    local btNode = btNodeItem:GetHudTrans()
    btNode.localPosition = Vector3.zero
    self._btNodeTrans = btNode

    CS.ShowObject(btNode,false)

    local hudDataList = self._hudDataList
    local hudShowList = {}
    self._hudShowList = hudShowList
    local hudShowData = nil

	local bChangeParent = false
    for k,v in ipairs(hudDataList) do
        hudShowData = self:CreateHud(v)

        table.insert(hudShowList,hudShowData)
		if hudShowData.hudType == LFightConst.HUD_BUFF then
			bChangeParent = true
		end
    end

    if bChangeParent then
        CS.SetParentTrans(btNode,self._wordRootTrans)
    else
        CS.SetParentTrans(btNode,self._parentTrans)
    end

    self._maxIndex = #hudShowList
end

--伤害类型转成hud的类型
function LFightHud:ConvertHudType(hudData)
    local changeType = hudData:GetChangeType()
    local hudType = LFightHud.HurtTypeToHudMap[changeType]
    if hudType then
        return hudType
    end

    hudType = hudData:GetDamageNumType()
    if not string.isempty(hudType) and LFightHud.HudTypeMap[hudType] then
        return hudType
    end

    printErrorN(string.format("LFightHud not hurt type %s | %s",changeType, tostring(hudType)))
    return LFightConst.HUD_COMMON
end

function LFightHud:CreateHud(hudData)
    local hudType = self:ConvertHudType(hudData)
    self._hudType = hudType

    local hudItem = self._battleCache:GetHudItemFromCache(hudType)
    CS.SetParentTrans(hudItem:GetHudTrans(),self._btNodeTrans)

    if hudType == LFightConst.HUD_TIP then
        return self:CreateTipHud(hudItem,hudData)
    elseif hudType == LFightConst.HUD_BUFF then
        return self:CreateBuffHud(hudItem,hudData)
    elseif hudType == LFightConst.HUD_SKILL then
        return self:CreateSkillHud(hudItem,hudData)
    elseif hudType == LFightConst.HUD_WORLD then
        return self:CreateWorldHud(hudItem,hudData)
    elseif hudType == LFightConst.HUD_TREA then
        return self:CreateTreaHud(hudItem,hudData)
    else
        return self:CreateNormal(hudItem,hudData)
    end
end

---@param hudItem LFightHudItem
function LFightHud:CreateTipHud(hudItem,hudData)
    local hudTrans = hudItem:GetHudTrans()
    self:SetTipImage(hudItem, self._text)
    local hudType = hudItem:GetHudType()
    return {hudType = hudType, hudItem = hudItem, trans = hudTrans, data = hudData,tween = nil}
end

---@param hudItem LFightHudItem
function LFightHud:CreateWorldHud(hudItem,hudData)
    local textStr = ccClientText(10917)
    local hudTrans = hudItem:GetHudTrans()
    local textTran = hudItem:FindTransWithName(hudTrans,"Text")
    CS.ShowObject(textTran,true)

    local textCom = hudItem:GetText(textTran)
    self:SetXTextContent(textCom,textStr)

    CS.ShowObject(hudTrans,false)
    return {hudType = hudItem:GetHudType(), hudItem=hudItem, trans = hudTrans, data=hudData,tween = nil}
end


---@param hudItem LFightHudItem
function LFightHud:CreateBuffHud(hudItem,hudData)
