---@param hudItem LFightHudItem
function LFightHud:CreateTreaHud(hudItem,hudData)
    if not gLGameUI:IsVisibleBattleFont() then return end

    local item = hudItem:GetHudTrans()

    local bgTrans = hudItem:FindTransWithName(item,"bg")
    local iconBg = hudItem:FindTransWithName(item,"iconBg")
    local iconBgIcon = hudItem:FindTransWithName(iconBg,"icon")
    local nameTrans = hudItem:FindTransWithName(item,"name")

    local skillId = self._hudPara.skillId
    local skillRef = gModelSkill:GetSkillRef(skillId)
    if skillRef then
        local nameIconPath = skillRef.nameIcon
        CS.ShowObject(nameTrans,false)
        local uiImage = hudItem:GetImage(nameTrans)
        self:SetImage(uiImage,nameIconPath,function ()
            CS.ShowObject(nameTrans,true)
        end,true)
    end
    local skillInfo = gModelDraconic:GetDraconicRefBySkillId(skillId)
    if skillInfo then
        local iconPath = skillInfo.skillIcon
        CS.ShowObject(iconBgIcon,false)
        local uiImage = hudItem:GetImage(iconBgIcon)
        self:SetImage(uiImage,iconPath,function ()
            CS.ShowObject(iconBgIcon,true)
        end,true)

        iconPath = skillInfo.skillbg
        CS.ShowObject(iconBg,false)
        local iconImage = hudItem:GetImage(iconBg)
        self:SetImage(iconImage,iconPath,function ()
            CS.ShowObject(iconBg,true)
        end,true)
    end

    CS.ShowObject(item,false)
    return {hudType = hudItem:GetHudType(), hudItem=hudItem, trans = item, data=hudData,tween = nil}
end

---@param hudItem LFightHudItem
function LFightHud:CreateNormal(hudItem,hudData)
    local hudTrans = hudItem:GetHudTrans()
    local hudType = hudItem:GetHudType()
    local pngTrans = hudItem:FindTransWithName(hudTrans,"Png")
    local imageTrans = hudItem:FindTransWithName(pngTrans,"Image")
    CS.ShowObject(imageTrans,false)

    local bAddNegative = false
    --当数字>7位数时，显示单位“万”，去尾显示（例如12345678=1234万）
    local fixedInfo = {limit=7, fontindex=11, pos=4}
    local textSize = 100
    local addPrefixStr = ""
    if hudType == LFightConst.HUD_HEAL or hudType == LFightConst.HUD_HURT then  -- 回血跟治疗都要加
        addPrefixStr = "<sprite index=10>"
    elseif hudType == LFightConst.HUD_STRIKE then
        addPrefixStr = "<sprite index=10>"
    elseif hudType == LFightConst.HUD_COMMON then
        bAddNegative = true
    end
    local hurt = math.floor(math.abs(hudData:GetHurt()))

    local changeType = hudData:GetChangeType()
    local text = ""
    if hurt ~= 0 or changeType == LFightConst.HURT_TYPE_GENERAL_ATTACK then
        text =string.format("%s%s",addPrefixStr,LUtil.FormatHurtNumSpriteText(hurt,bAddNegative,textSize, fixedInfo))
    end

    local txtPosX, textWidth = self:SetDamageTypeIconText(hudItem,hudData:GetDamageTypeIconName(),text)

    CS.ShowObject(hudTrans,false)
    return {hudType = hudType, hudItem=hudItem, trans = hudTrans, data=hudData,tween = nil, textPosX=txtPosX, textWidth=textWidth}
end

--获取对象当前坐标在ui坐标中的映射位置
function LFightHud:GetObjPos()
    local obj = self._objPos
    if obj then
        local objPos = obj
        if not objPos then return Vector3.zero end
        local sceneCamera = gLGameScene:GetCurrentSceneCamera()
        local uiSceneCamrea = LGameUI.GetUICamera()
        objPos = Vector3(objPos.x,objPos.y,0)
        --坐标轴转换：将角色位置坐标，转化为屏幕坐标。屏幕坐标转化为世界坐标，设置UI坐标。
        local screenPos  = sceneCamera:WorldToScreenPoint(objPos) --Vector3
        local worldPos = uiSceneCamrea:ScreenToWorldPoint(screenPos)
        worldPos.z = 0
        return worldPos
    end
end

--根据buff文本内容让飘字保持相对居中
---@param hudItem LFightHudItem
function LFightHud:SetBUFFText(hudItem)
    local parentTrans = hudItem:GetHudTrans()
    --有图标的buff文本
    local itemRoot = hudItem:FindTransWithName(parentTrans,"ItemRoot")
    --无图标的buff文本
    local pureTextTrans = hudItem:FindTransWithName(parentTrans,"PureText")
	CS.ShowObject(pureTextTrans,false)
	CS.ShowObject(itemRoot,false)

    if not gLGameUI:IsVisibleBattleFont() then return
    end

	local addOrReduceBuff = tonumber(self._addOrReduceBuff)
    if addOrReduceBuff == LFightConst.HUD_ICON_FAVORABLE or addOrReduceBuff == LFightConst.HUD_ICON_HARMFUL then
		local buffCountTrans = hudItem:FindTransWithName(itemRoot,"BuffCount")
		local upImageTrans = hudItem:FindTransWithName(buffCountTrans,"UPImage")
		local downImageTrans = hudItem:FindTransWithName(buffCountTrans,"DownImage")
		local color
        if addOrReduceBuff == LFightConst.HUD_ICON_FAVORABLE then
            color = LFightHud.GREEN
            CS.ShowObject(upImageTrans,true)
            CS.ShowObject(downImageTrans,false)
        elseif addOrReduceBuff == LFightConst.HUD_ICON_HARMFUL then
            color = LFightHud.BLUE
            CS.ShowObject(upImageTrans,false)
            CS.ShowObject(downImageTrans,true)
        end

		CS.ShowObject(itemRoot,true)

		local textBuffTrans = hudItem:FindTransWithName(buffCountTrans,"TextBuff")
		local curBuffText = hudItem:GetText(textBuffTrans)
        --计算图标+文本内容实际宽度调整飘字大小
        local str = string.format("<color=#%s>%s</color>", color, self._text)
        self:SetXTextContent(curBuffText,str)
		
        local curBuffTextWitch = curBuffText.preferredWidth
		local imageWitch = 14
		local buffCountRectTrans = buffCountTrans
        if buffCountRectTrans then
            local size = Vector2.New((curBuffTextWitch + imageWitch), buffCountRectTrans.rect.height)
            buffCountRectTrans.sizeDelta = size
        end
    elseif addOrReduceBuff == LFightConst.HUD_ICON_BUFF_TEXT then
		local textContentStr = string.format("<color=#%s>%s</color>", LFightHud.ORANGE, self._text)
        local pureText = hudItem:GetText(pureTextTrans)
        CS.ShowObject(pureTextTrans,true)
        if pureText then
            self:SetXTextContent(pureText,textContentStr)
        end
    end
end

function LFightHud:SetSkillImage(hudItem)
    local parentTrans = hudItem:GetHudTrans()
    if not gLGameUI:IsVisibleBattleFont() then
        CS.ShowObject(parentTrans, false)
        return
    end

    local skillId = self._hudPara.skillId
    local skillRef = gModelSkill:GetSkillRef(skillId)
    local nameIconPath = skillRef.nameIcon
    local trans = hudItem:FindTransWithName(parentTrans,"Bg")
    CS.ShowObject(trans,false)
    if string.isempty(nameIconPath) then
        if LOG_INFO_ENABLED then
            printErrorN(string.format("no skill image refid %s ",skillId))
        end
        return
    end
    local uiImage = hudItem:GetImage(trans)
    self:SetImage(uiImage,nameIconPath,function ()
        if CS.IsValidObject(trans) then
            CS.ShowObject(trans,true)
        end
    end)
end

---@param hudItem LFightHudItem
function LFightHud:SetDamageTypeIconText(hudItem,imagePath,textStr)
    if not gLGameUI:IsVisibleBattleFont() then return end

    local parentTrans = hudItem:GetHudTrans()
    local trans = hudItem:FindTransWithName(parentTrans,"Png")
    if trans then
        local imageTrans = hudItem:FindTransWithName(trans,"Image")
        local textTrans = hudItem:FindTransWithName(parentTrans,"Text")
        local image = hudItem:GetImage(imageTrans)

        CS.ShowObject(imageTrans,true)
        CS.ShowObject(textTrans,not string.isempty(textStr))

        local textCom = hudItem:GetText(textTrans)
        self:SetXTextContent(textCom,textStr)

        self:SetHurtTextSize(textTrans)

        if not string.isempty(imagePath) then
            CS.ShowObject(trans,false)
            self:SetImage(image,imagePath, function()
                if not CS.IsValidObject(trans) then return end

                local curWitch = image.preferredWidth
                local rectTrans = trans
                local offectX = (curWitch / 2) + 30

                if rectTrans then
                    local size = Vector2.New(curWitch, rectTrans.rect.height)
                    rectTrans.sizeDelta = size
                end
                CS.ShowObject(trans,true)
                trans.localPosition = Vector3(textTrans.localPosition.x - offectX,trans.localPosition.y,0)
            end,true)
        else
            CS.ShowObject(trans,false)
        end
        return textCom.preferredWidth, textTrans.localPosition.x - textTrans.sizeDelta.x / 2
    else
        local textTrans = hudItem:FindTransWithName(parentTrans,"Text")
        local textCom = hudItem:GetText(textTrans)
        self:SetXTextContent(textCom,textStr)

        self:SetHurtTextSize(textTrans)

        return textCom.preferredWidth, textTrans.localPosition.x - textTrans.sizeDelta.x / 2
    end

end

---@param hudItem LFightHudItem
function LFightHud:SetTipImage(hudItem,imagePath)
    local parentTrans = hudItem:GetHudTrans()
    local trans = hudItem:FindTransWithName(parentTrans, "Png")
    if not trans then
        return
    end
    local imageTrans = hudItem:FindTransWithName(trans,"Image")
    local textTrans = hudItem:FindTransWithName(parentTrans,"Text")
    local uiImage = hudItem:GetImage(imageTrans)
    self:SetImage(uiImage,imagePath,function ()
        if not CS.IsValidObject(trans) then return end

        CS.ShowObject(trans,true)
        local pos = Vector2.New(parentTrans.rect.width/2,-parentTrans.rect.height/2)
        trans.anchoredPosition = pos
    end ,true)
    CS.ShowObject(imageTrans,true)
    CS.ShowObject(textTrans,false)
end


function LFightHud:SetHurtTextSize(trans)
    local isForeign = gLGameLanguage:IsForeignVersion()
    if not isForeign then return end

    LxUiHelper.SetTextFontSize(trans,30)
    local uiText = LxUiHelper.FindXTextCtrl(trans)
    uiText.characterSpacing = -15
end

-----------------------------------------------------------------
function LFightHud:OnRun(time)
    if self:IsDestroy() then return false end

    if not self._isStart then return end

    if not self._isPlaying then
        if self._startTime <= time then
            self:InitHud()
        end
    end

    if self._isPlaying then
        if self._playendCount >= self._maxIndex then
            return false
        end
        if not self._isLast then
            if not self._nextDelay then return false end

            time = time - self._startTime
            if self._nextDelay <= time then
                self:ShowNextHud()
            end
        end
    end

    return true
end
-----------------------------------------------------------------
function LFightHud:Destroy()
    if self._hudShowList then
        local battleCache = self._battleCache
        for _,v in ipairs(self._hudShowList) do
            if v.tween then v.tween:Kill(false) end
            v.tween = nil
            v.trans = nil
            if v.hudItem then
                battleCache:ReturnHudItemToCache(v.hudType,v.hudItem)
            end
            v.hudItem = nil
        end
        self._hudShowList = nil
    end

    if self._btNodeItem  then
        local btHudFollow = self._btHudFollow
        if btHudFollow then
            btHudFollow:ClearFollow()
        end
        self._btHudFollow = nil
        self._battleCache:ReturnHudItemToCache(LFightConst.HUD_BTNODE,self._btNodeItem)
        self._btNodeItem = nil
    end

    LxNodeBase.Dispose(self)

    self._isDestroyed = true
end

function LFightHud:IsDestroy()
    return self._isDestroyed
end

return LFightHud